agent_output:
{
  "executive_summary": "The courier assignment system has a fundamental tension between strong consistency (no double-assignment) and high availability (survive DB node failure), which is a textbook CAP theorem conflict. For a 2-engineer team, the architecture must be ruthlessly simple. I recommend a single-writer pattern with a PostgreSQL primary + synchronous standby, using SELECT FOR UPDATE SKIP LOCKED for atomic courier claiming. This prioritizes consistency (CP) while achieving practical availability through automated failover, and hits the 200ms latency target via in-memory pre-filtering of eligible couriers. The product team should be made aware that during a failover window (~5-15 seconds), assignments will be unavailable — this is the honest trade-off of guaranteeing no double-assignments.",

  "architecture": {
    "components": [
      {
        "name": "Assignment Service",
        "responsibility": "Receives order-placed events, selects the best eligible courier, and atomically claims them. Stateless — all state lives in PostgreSQL. Horizontally scalable since contention is managed by the DB lock.",
        "boundaries": "Owns the courier availability model and assignment transaction. Does NOT own order lifecycle or courier tracking/location."
      },
      {
        "name": "Courier Availability Cache",
        "responsibility": "In-process (not Redis) materialized view of available couriers with last-known location and current load. Rebuilt on startup from DB, kept warm via CDC/LISTEN-NOTIFY. Used for pre-filtering candidates BEFORE the DB lock — this is how we hit 200ms.",
        "boundaries": "Read-only, eventually consistent. Never used as source of truth for assignment decisions — only for narrowing candidates."
      },
      {
        "name": "PostgreSQL Primary + Synchronous Standby",
        "responsibility": "Single source of truth for courier assignments. The `courier_assignments` table with a UNIQUE constraint on (courier_id, status=ACTIVE) enforces the no-double-assignment invariant at the database level. Synchronous replication to standby ensures no committed assignment is lost on failover.",
        "boundaries": "Owns all persistent state. Patroni or pg_auto_failover manages promotion."
      },
      {
        "name": "Failover Manager (Patroni)",
        "responsibility": "Monitors primary health, promotes synchronous standby to primary on failure. Provides a single VIP/endpoint so the Assignment Service doesn't need to track topology.",
        "boundaries": "Infrastructure concern only. No application logic."
      }
    ],
    "interfaces": [
      {
        "from": "Order Service",
        "to": "Assignment Service",
        "contract": "POST /assignments {order_id, pickup_location, delivery_location} → {assignment_id, courier_id} | 409 CONFLICT | 503 UNAVAILABLE. Synchronous HTTP call with 200ms timeout.",
        "coupling_type": "synchronous request-response (tight, intentional — latency requirement demands it)"
      },
      {
        "from": "Assignment Service",
        "to": "PostgreSQL",
        "contract": "Single transaction: BEGIN → SELECT courier_id FROM available_couriers WHERE zone = $1 AND status = 'AVAILABLE' ORDER BY score LIMIT 1 FOR UPDATE SKIP LOCKED → INSERT INTO assignments → UPDATE courier status → COMMIT. Total DB time budget: <50ms.",
        "coupling_type": "tight (unavoidable — DB is the consistency mechanism)"
      },
      {
        "from": "Assignment Service",
        "to": "Courier Availability Cache",
        "contract": "In-process function call: get_candidates(zone, pickup_location) → List<CourierId>. Filters by zone and proximity to reduce the DB query scope from thousands of couriers to ~10-50 candidates.",
        "coupling_type": "loose (cache miss = slightly wider DB query, not a failure)"
      },
      {
        "from": "Courier Tracking Service",
        "to": "Assignment Service",
        "contract": "Async events via LISTEN/NOTIFY or lightweight message queue: courier_available, courier_offline, courier_location_updated. These refresh the in-process cache.",
        "coupling_type": "loose async (eventual consistency acceptable for pre-filtering)"
      }
    ],
    "data_flow": "1. Order Service calls Assignment Service synchronously. 2. Assignment Service checks in-process cache to identify top ~10 candidate couriers in the zone. 3. Assignment Service executes a single atomic transaction: SELECT FOR UPDATE SKIP LOCKED on those candidates, picks the best available one, inserts assignment, updates courier status. 4. Returns courier_id to Order Service. 5. If no courier available or DB unreachable, returns appropriate error for retry. Total path: ~20ms cache lookup + ~50ms DB transaction + ~30ms network overhead = well under 200ms.",
    "patterns_used": [
      {
        "pattern": "SELECT FOR UPDATE SKIP LOCKED (Pessimistic Locking with Skip)",
        "rationale": "This is the critical pattern. SKIP LOCKED means concurrent assignment requests don't block each other — if courier A is being claimed by transaction 1, transaction 2 skips to courier B. This gives us both strong consistency AND low latency under concurrency. Without SKIP LOCKED, concurrent requests would serialize on the same row and blow the 200ms budget."
      },
      {
        "pattern": "Single-Writer Database (CP choice)",
        "rationale": "CAP theorem forces a choice. Since double-assignment has real-world cost (two couriers show up, customer confusion, wasted labor), we choose CP. A single PostgreSQL primary is the write authority. Availability is achieved through fast automated failover, not through multi-writer replication."
      },
      {
        "pattern": "In-Process Materialized Cache",
        "rationale": "Avoids a network hop to Redis. For a 2-engineer team, one fewer infrastructure component to operate. The cache narrows the candidate set so the DB query touches few rows, keeping transaction time under 50ms."
      },
      {
        "pattern": "Database-Level Invariant Enforcement",
        "rationale": "A partial unique index — CREATE UNIQUE INDEX ON assignments(courier_id) WHERE status = 'ACTIVE' — makes double-assignment physically impossible regardless of application bugs. Defense in depth: the application logic prevents it, the database guarantees it."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Courier Assignment",
        "classification": "core",
        "aggregates": [
          "Assignment (root: assignment_id; invariant: one active assignment per courier; entities: Assignment; value objects: PickupLocation, DeliveryLocation, AssignmentStatus)",
          "CourierAvailability (root: courier_id; invariant: status transitions are valid — AVAILABLE→ASSIGNED→DELIVERING→AVAILABLE; value objects: Zone, Location, CapacityScore)"
        ]
      },
      {
        "name": "Order Management",
        "classification": "supporting",
        "aggregates": ["Order (external — we only consume order_id and locations)"]
      },
      {
        "name": "Courier Tracking",
        "classification": "supporting",
        "aggregates": ["CourierPosition (external — we consume location updates)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Courier Assignment",
        "relationship": "Customer-Supplier. Order Management requests assignment; Assignment Service owns the decision logic. ACL translates order data into assignment-domain terms."
      },
      {
        "upstream": "Courier Tracking",
        "downstream": "Courier Assignment",
        "relationship": "Conformist for location data. Assignment consumes tracking events as-is to update its availability cache. Low coupling — stale location data degrades optimality, not correctness."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "CP over AP — single-writer PostgreSQL",
      "gains": "Absolute guarantee of no double-assignment. Simple mental model. Single source of truth.",
      "sacrifices": "During failover (~5-15 seconds), assignments are unavailable. Orders placed during this window must be queued or retried.",
      "alternatives_considered": [
        "Multi-writer with conflict resolution (AP): Enables writes during partition, but conflict resolution for courier assignment is inherently lossy — you'd have to revoke one assignment after the fact, which is worse than a brief outage.",
        "Distributed lock (Redis Redlock): Adds infrastructure complexity, and Redlock has known safety issues under network partitions (see Martin Kleppmann's analysis). Not appropriate for a 2-person team.",
        "Event sourcing with saga: Elegant but massive complexity overhead for a small team. Overkill for this domain."
      ]
    },
    {
      "decision": "In-process cache over Redis",
      "gains": "Zero network latency for candidate pre-filtering. One fewer infrastructure component to deploy, monitor, and debug. Simpler failure modes.",
      "sacrifices": "Each service instance has its own cache — slightly more memory usage. Cache can be briefly stale after a courier status change (acceptable: SKIP LOCKED handles the race).",
      "alternatives_considered": [
        "Redis: Shared cache, but adds ~2-5ms per lookup, a new failure mode, and operational burden. Not justified for a 2-person team."
      ]
    },
    {
      "decision": "Synchronous HTTP over async event-driven assignment",
      "gains": "Caller gets immediate confirmation of assigned courier. Simple request-response. Matches the 200ms latency requirement naturally.",
      "sacrifices": "Tight coupling between Order Service and Assignment Service at call time. If Assignment Service is down, order placement is degraded.",
      "alternatives_considered": [
        "Async with callback: Would decouple services but add complexity (callback handling, timeout logic, compensation). The 200ms requirement implies the caller wants a synchronous answer."
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Courier scoring algorithm",
      "evolution_path": "The scoring logic (which courier to prefer) is isolated in the candidate selection phase. Can evolve from simple proximity-based scoring to ML-based optimization without changing the assignment transaction or database schema."
    },
    {
      "area": "Scaling the read path",
      "evolution_path": "The in-process cache pattern can evolve to a dedicated read replica or CQRS model if query patterns become complex. The write path (assignment transaction) stays unchanged."
    },
    {
      "area": "Assignment strategy",
      "evolution_path": "Currently assigns best single courier. Can evolve to batch assignment (assign N orders simultaneously for global optimum) by changing the service layer without touching the DB constraint model."
    }
  ],

  "rigidity_points": [
    {
      "area": "PostgreSQL as consistency mechanism",
      "reason": "The entire no-double-assignment guarantee depends on PostgreSQL's transactional semantics and the partial unique index. Migrating to a different database would require re-engineering the core invariant enforcement. This is intentional rigidity — the invariant is too important to abstract."
    },
    {
      "area": "Single-primary write topology",
      "reason": "Cannot switch to multi-region active-active writes without fundamentally changing the consistency model. If multi-region becomes a requirement, this is a redesign, not a config change."
    }
  ],

  "risks": [
    {
      "risk": "Failover window causes order assignment failures for 5-15 seconds",
      "severity": "high",
      "mitigation": "Implement client-side retry with exponential backoff in Order Service. Queue orders during failover window. Set SLA expectation with product team: 99.95% availability (not 99.99%). Monitor failover frequency — if hardware is unstable, invest in better infrastructure rather than architectural complexity."
    },
    {
      "risk": "Hot courier rows under extreme concurrency (e.g., flash sale in one zone)",
      "severity": "medium",
      "mitigation": "SKIP LOCKED eliminates row-level contention. If all couriers in a zone are locked simultaneously, the query returns no rows — handle gracefully with a 'no courier available, retry in N seconds' response. Pre-filter by zone to spread load across different row sets."
    },
    {
      "risk": "In-process cache diverges significantly from DB state",
      "severity": "medium",
      "mitigation": "Cache is only used for pre-filtering, not for assignment decisions. Worst case of stale cache: we query a few couriers who turn out to be unavailable, SKIP LOCKED skips them, and we pick another. Add a periodic full-refresh (every 30s) as a safety net alongside event-driven updates."
    },
    {
      "risk": "Team of 2 struggles with operational burden of Patroni + PostgreSQL HA",
      "severity": "medium",
      "mitigation": "Use a managed PostgreSQL service (AWS RDS, Google Cloud SQL, or Supabase) with built-in HA and automated failover. This eliminates the need to operate Patroni. The managed service cost is trivially justified by the engineering time saved."
    },
    {
      "risk": "200ms SLA violated under p99 due to GC pauses or network jitter",
      "severity": "low",
      "mitigation": "Budget is generous: ~100ms of headroom in the happy path. Use connection pooling (PgBouncer or built-in pool) to eliminate connection setup time. Monitor p99 latency from day one. If JVM-based, tune GC; if Go/Rust, this is unlikely to be an issue."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1 (Week 1-2): PostgreSQL schema with partial unique index, Assignment Service with direct DB transaction (no cache yet — just query available couriers with FOR UPDATE SKIP LOCKED). This alone will work under moderate load and proves the correctness model. Phase 2 (Week 3): Add in-process courier availability cache fed by LISTEN/NOTIFY to hit 200ms consistently at higher throughput. Phase 3 (Week 4): Add Grafana dashboards for assignment latency p50/p95/p99, failover monitoring, and cache hit rates. Ship to production with managed PostgreSQL HA.",
    "files_to_create_or_modify": [
      "schema/001_create_assignments.sql — assignments table with partial unique index, courier_availability table",
      "src/assignment_service.rs (or .go/.ts) — HTTP handler + assignment transaction logic",
      "src/courier_cache.rs — in-process cache with LISTEN/NOTIFY refresh",
      "src/scoring.rs — courier scoring/ranking algorithm (isolated for easy evolution)",
      "tests/test_no_double_assignment.rs — concurrent assignment test that spawns N threads all trying to assign in the same zone",
      "tests/test_skip_locked_behavior.rs — verifies that concurrent transactions don't block each other",
      "docker-compose.yml — local dev with PostgreSQL primary + standby for failover testing"
    ],
    "patterns_to_follow": "Keep the assignment transaction in a single function — do not scatter it across layers. The function should: (1) get candidates from cache, (2) open transaction, (3) SELECT FOR UPDATE SKIP LOCKED, (4) INSERT assignment, (5) UPDATE courier status, (6) COMMIT. If any step fails, the transaction rolls back and no state is corrupted. This is your invariant boundary — treat it like a sacred ritual.",
    "pitfalls_to_avoid": [
      "Do NOT use application-level locks (mutexes, distributed locks) — the database IS your lock manager. Application locks add complexity and don't survive process crashes.",
      "Do NOT use SELECT FOR UPDATE without SKIP LOCKED — under concurrency, transactions will queue up and blow your latency budget.",
      "Do NOT put a message queue between Order Service and Assignment Service — the 200ms requirement means you need synchronous request-response.",
      "Do NOT build a microservice per component — with 2 engineers, a single deployable service with clear module boundaries is the right call. Extract services later if the team grows.",
      "Do NOT use an ORM for the assignment transaction — write the SQL explicitly. The SKIP LOCKED behavior and partial index are too important to risk an ORM abstracting them away.",
      "Do NOT attempt multi-region active-active — it contradicts the strong consistency requirement. Be honest about this constraint with stakeholders."
    ]
  },

  "escalations": [
    {
      "type": "missing_constraints",
      "description": "The requirements state 'high availability' and 'strong consistency' simultaneously, which is a CAP theorem impossibility during network partitions. The product team needs to explicitly acknowledge the trade-off: during a database failover (5-15 seconds), assignment requests will fail. If this is unacceptable, the no-double-assignment requirement must be relaxed to 'detect and resolve double-assignments within N seconds' — a fundamentally different (and more complex) architecture.",
      "options": [
        "Option A (Recommended): CP with fast failover — strong consistency always, ~99.95% availability, 5-15 second outage during failover",
        "Option B: AP with conflict resolution — always available, but double-assignments can occur during partitions and must be detected/revoked after the fact",
        "Option C: CP with manual queue — during failover, orders are queued and assigned when DB recovers, adding latency but preserving availability semantics"
      ],
      "recommendation": "Option A. The cost of a double-assignment (two couriers dispatched, customer confusion, wasted labor, refund) far exceeds the cost of a 10-second assignment delay during rare failover events. Confirm with the product team."
    }
  ],

  "confidence": {
    "level": 55,
    "high_confidence_areas": [
      "SELECT FOR UPDATE SKIP LOCKED is the correct concurrency primitive — well-proven in job queue and assignment systems",
      "Single-writer PostgreSQL is the right consistency choice for a 2-person team",
      "In-process cache over Redis for this team size and latency requirement",
      "The partial unique index as a database-level safety net against double-assignment"
    ],
    "low_confidence_areas": [
      "Exact failover timing depends on infrastructure choice (managed vs self-hosted) — needs validation",
      "Whether 200ms is a p50, p95, or p99 target changes the design pressure significantly",
      "Geographic distribution requirements are unknown — multi-region would invalidate this entire design",
      "Expected order volume and concurrency level (10 orders/sec vs 10,000 orders/sec) would change scaling recommendations"
    ],
    "assumptions": [
      "Single-region deployment",
      "Order volume under ~1,000 assignments/second (beyond this, the DB transaction model needs benchmarking)",
      "200ms is a p95 target, not p99",
      "The product team will accept a brief unavailability window during DB failover in exchange for absolute consistency",
      "Managed PostgreSQL (RDS/Cloud SQL) is available and acceptable"
    ]
  }
}
